arguments.file_text:
@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card mt-2">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@saving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(error))
            {
                <div class="text-danger small mt-1">@error</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? error;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
        error = null;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        saving = true;
        error = null;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
            IsVisible = false;
            ResetForm();
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            saving = false;
        }
    }
}

@page "/board"
@using sv_91c00bab2b2f47ce967a1d7c8e4a88d2.Components.Board
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="TodoTasks.Count"
                   InProgressCount="InProgressTasks.Count"
                   DoneCount="DoneTasks.Count"
                   OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@searchText" SearchTextChanged="OnSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="id => MoveTask(id, \"In Progress\")"
                      OnAddTask="args => AddTask(args, \"To Do\")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, \"To Do\")"
                      OnMoveRight="id => MoveTask(id, \"Done\")"
                      OnAddTask="args => AddTask(args, \"In Progress\")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, \"In Progress\")"
                      OnAddTask="args => AddTask(args, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    // Unfiltered column lists (used for stats)
    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();

    // Filtered column lists (used for display)
    private List<TaskItem> FilteredTodo => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgress => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDone => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private void OnSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
        var task = allTasks.First(t => t.Id == taskId);
        allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
        allTasks.Add(created);
    }
}

