@page "/board"
@using sv_91c00bab2b2f47ce967a1d7c8e4a88d2.Components.Board
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="TodoTasks.Count"
                   InProgressCount="InProgressTasks.Count"
                   DoneCount="DoneTasks.Count"
                   OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@searchText" SearchTextChanged="OnSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="id => MoveTask(id, \"In Progress\")"
                      OnAddTask="args => AddTask(args, \"To Do\")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, \"To Do\")"
                      OnMoveRight="id => MoveTask(id, \"Done\")"
                      OnAddTask="args => AddTask(args, \"In Progress\")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDone"
                      CanMoveLeft="true"
